  "result": [
    {
      "name": "gwas_get_associations_by_disease",
      "description": "Retrieve genome-wide significant GWAS associations for a disease from the NHGRI-EBI GWAS Catalog REST API. Accepts EFO IDs (e.g., EFO_0000249) or MONDO IDs (auto-mapped to EFO).",
      "parameter": {
        "type": "object",
        "properties": {
          "efo_id": {
            "type": "str",
            "description": "EFO ID of the disease (e.g., \"EFO_0000249\" for Alzheimer's disease). MONDO IDs such as \"MONDO_0004975\" are automatically mapped to the correct GWAS Catalog EFO ID.",
            "required": true
          },
          "p_value_threshold": {
            "type": "float",
            "description": "P-value threshold for significance (default: 5e-8).",
            "required": true
          }
        }
      },
      "required": [
        "efo_id",
        "p_value_threshold"
      ],
      "source": "custom_registry"
    }
  ]
}

